// ─── Atoms ────────────────────────────────────────────────────────────────────
function Badge({ color="blue", children }) {
  const s = {
    blue:{bg:C.blueLight,text:C.blue}, gold:{bg:C.goldLight,text:C.gold},
    green:{bg:C.greenLight,text:C.green}, gray:{bg:"#f0f0ee",text:C.muted},
    red:{bg:"#fce4ec",text:C.red}, kemasan:{bg:"#f3e5f5",text:"#6a1b9a"},
    cleaning:{bg:"#e8f5e9",text:C.green}, baru:{bg:"#fff3e0",text:"#b8540a"},
  }[color] || {bg:C.blueLight,text:C.blue};
  return <span style={{background:s.bg,color:s.text,fontSize:10,fontWeight:600,
    padding:"2px 6px",borderRadius:3,display:"inline-block",whiteSpace:"nowrap"}}>{children}</span>;
}

function IconBtn({ title, onClick, color, children }) {
  const [hov, setHov] = useState(false);
  return <button title={title} onClick={onClick}
    onMouseEnter={()=>setHov(true)} onMouseLeave={()=>setHov(false)}
    style={{background:hov?(color==="red"?"#fce4ec":C.blueLight):"transparent",
      border:"none",borderRadius:4,cursor:"pointer",
      color:hov?(color==="red"?C.red:C.blue):C.muted,
      padding:"3px 5px",fontSize:13,lineHeight:1,transition:"all 0.15s",
      display:"inline-flex",alignItems:"center"}}>{children}</button>;
}

// ─── Auto-resize textarea ─────────────────────────────────────────────────────
function AutoTA({ value, onChange, disabled, placeholder }) {
  const ref = useRef();
  useEffect(() => {
    const el = ref.current; if (!el) return;
    el.style.height = "auto";
    el.style.height = el.scrollHeight + "px";
  }, [value]);
  return <textarea ref={ref} value={value} onChange={e=>onChange(e.target.value)}
    disabled={disabled} placeholder={placeholder} rows={1}
    style={{width:"100%",border:disabled?"none":`1px solid ${C.border}`,borderRadius:disabled?0:3,
      fontFamily:font,fontSize:12,padding:disabled?"2px 0":"6px 8px",resize:"none",
      color:disabled?C.muted:C.text,background:disabled?"transparent":C.bg,
      lineHeight:1.6,overflow:"hidden",minHeight:28,outline:"none",
      cursor:disabled?"default":"text",opacity:disabled?0.75:1,
      boxSizing:"border-box",display:"block"}}
    onFocus={e=>{if(!disabled)e.target.style.borderColor=C.blue;}}
    onBlur={e=>{if(!disabled)e.target.style.borderColor=C.border;}} />;
}

// ─── BPJPH Search ─────────────────────────────────────────────────────────────
async function fakeBPJPH(query) {
  await new Promise(r=>setTimeout(r,500+Math.random()*300));
  if (!query.trim()) return [];
  const lower = query.toLowerCase();
  const DB = [
    {id:"ID00410000476250922",nama:"ANCHOR Unsalted Butter",produsen:"PT. Fonterra Brands Indonesia",tgl:"2022-10-13",exp:"2025-10-13",jenis:"Bahan"},
    {id:"ID00410000002160320",nama:"ANCHOR FP Keju Cheddar Olahan",produsen:"PT. Fonterra Brands Indonesia",tgl:"2025-08-05",exp:"2028-08-05",jenis:"Bahan"},
    {id:"ID00410000500550822",nama:"Barry Callebaut Dark Chocolate",produsen:"Barry Callebaut Chocolate Asia Pacific Pte Ltd",tgl:"2022-10-27",exp:"2025-10-27",jenis:"Bahan"},
    {id:"ID31110021166460325",nama:"Whipping Cream Millac Gold",produsen:"Cv. Permata Tunggal",tgl:"2025-03-15",exp:"2028-03-15",jenis:"Bahan"},
    {id:"ID00410000201600321",nama:"Gulaku Premium",produsen:"PT Sweet Indolampung",tgl:"2021-06-17",exp:"2024-06-17",jenis:"Bahan"},
    {id:"ID00410000090970121",nama:"Tepung Terigu Segitiga Biru",produsen:"PT. Indofood Sukses Makmur Tbk",tgl:"2021-03-25",exp:"2024-03-25",jenis:"Bahan"},
    {id:"ID00410000264060622",nama:"Cocoa Powder BENSDORP",produsen:"Papandayan Cocoa Industries",tgl:"2022-07-21",exp:"2025-07-21",jenis:"Bahan"},
    {id:"ID36110028397440925",nama:"Soft Box Fuji Pratama",produsen:"PT. Fuji Pratama Global",tgl:"2025-09-20",exp:"2028-09-20",jenis:"Kemasan"},
    {id:"ID00410000008400120",nama:"SUNLIGHT Cairan Pencuci Piring",produsen:"PT. Unilever Indonesia Tbk",tgl:"2024-06-03",exp:"2027-06-03",jenis:"Cleaning Agent"},
    {id:"ID00410000476720822",nama:"Baking Paper Dragon Pack",produsen:"PT. Dragon Pack",tgl:"2022-10-13",exp:"2025-10-13",jenis:"Kemasan"},
  ];
  return DB.filter(r=>r.nama.toLowerCase().includes(lower)||r.produsen.toLowerCase().includes(lower)||r.id.toLowerCase().includes(lower));
}

function fmtTgl(iso) {
  if (!iso) return "—";
  return fmtDate(iso);
}
function isExpired(exp) { return exp && new Date(exp) < new Date(); }
function buildTemuan(item) {
  return `SH BPJPH ${item.id}, terbit tanggal ${fmtTgl(item.tgl)}, dari Produsen ${item.produsen}`;
}

function BPJPHModal({ onClose, onSelect }) {
  const [q,setQ]=useState(""); const [res,setRes]=useState([]); const [loading,setLoading]=useState(false); const [searched,setSearched]=useState(false);
  const ref = useRef(); useEffect(()=>ref.current?.focus(),[]);
  const search = useCallback(async()=>{ if(!q.trim())return; setLoading(true);setSearched(true); setRes(await fakeBPJPH(q)); setLoading(false); },[q]);
  return <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.45)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:1000,padding:16}}
    onClick={e=>e.target===e.currentTarget&&onClose()}>
    <div style={{background:C.bg,borderRadius:8,width:"100%",maxWidth:560,boxShadow:"0 8px 32px rgba(0,0,0,0.18)",
      border:`1px solid ${C.border}`,fontFamily:font,maxHeight:"80vh",display:"flex",flexDirection:"column"}}>
      <div style={{background:C.blue,color:"#fff",padding:"12px 16px",borderRadius:"8px 8px 0 0",
        display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <span style={{fontWeight:600,fontSize:13}}>🔍 Cari Bahan — Database BPJPH</span>
        <button onClick={onClose} style={{background:"none",border:"none",color:"#fff",cursor:"pointer",fontSize:18}}>×</button>
      </div>
      <div style={{padding:"12px 16px",borderBottom:`1px solid ${C.borderLight}`,display:"flex",gap:8}}>
        <input ref={ref} value={q} onChange={e=>setQ(e.target.value)}
          onKeyDown={e=>{if(e.key==="Enter")search();if(e.key==="Escape")onClose();}}
          placeholder="Nama bahan, produsen, atau nomor SH..."
          style={{flex:1,border:`1px solid ${C.border}`,borderRadius:5,padding:"7px 10px",fontSize:13,fontFamily:font,outline:"none"}}/>
        <button onClick={search} style={{background:C.blue,color:"#fff",border:"none",borderRadius:5,
          padding:"7px 16px",fontSize:13,fontWeight:600,cursor:"pointer",fontFamily:font}}>Cari</button>
      </div>
      <div style={{overflowY:"auto",flex:1}}>
        {loading&&<div style={{padding:24,textAlign:"center",color:C.muted,fontSize:13}}>Mengambil data BPJPH…</div>}
        {!loading&&searched&&res.length===0&&<div style={{padding:24,textAlign:"center",color:C.muted,fontSize:13}}>Tidak ditemukan.</div>}
        {!loading&&res.map((r,i)=><div key={i} style={{padding:"10px 16px",borderBottom:`1px solid ${C.borderLight}`,
          display:"flex",alignItems:"flex-start",gap:12,background:i%2===0?C.bg:C.bgAlt}}>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontWeight:600,fontSize:12,marginBottom:2}}>{r.nama}</div>
            <div style={{fontSize:11,color:C.muted,marginBottom:3}}>{r.produsen}</div>
            <div style={{fontSize:10,fontFamily:mono,color:C.blue}}>{r.id}</div>
            <div style={{fontSize:10,color:isExpired(r.exp)?C.red:"#2e7d32",marginTop:2}}>
              {isExpired(r.exp)?"⚠ Kadaluarsa ":"✓ Berlaku s/d "}{fmtTgl(r.exp)}
            </div>
          </div>
          <button onClick={()=>onSelect(r)} style={{background:C.blue,color:"#fff",border:"none",borderRadius:5,
            padding:"6px 12px",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:font,flexShrink:0}}>
            ← Tambah
          </button>
        </div>)}
        {!loading&&!searched&&<div style={{padding:20,textAlign:"center",color:C.faint,fontSize:12}}>
          Ketik nama bahan, produsen, atau nomor SH lalu tekan Enter.
        </div>}
      </div>
    </div>
  </div>;
}

