// ─── Produk Table ─────────────────────────────────────────────────────────────
function ProdukTable({ isAuditor }) {
  const [rows,setRows]=useState([
    {id:1,nama:"Bihun Goreng Sapi - Kembang Muda"},
    {id:2,nama:"Kwetiau Goreng Sapi - Kembang Muda"},
    {id:3,nama:"Mie Goreng Sapi - Kembang Muda"},
    {id:4,nama:"Nasi Goreng Sapi - Kembang Muda"},
    {id:5,nama:"Pisang Goreng Coklat Keju - Kembang Muda"},
  ]);
  const [adding,setAdding]=useState(false);
  const [newNama,setNewNama]=useState("");
  const th = {background:C.blue,color:"#fff",fontWeight:500,fontSize:11,padding:"6px 8px",textAlign:"left"};

  return <div style={{fontFamily:font}}>
    <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
      <colgroup><col style={{width:36}}/><col/>{isAuditor&&<col style={{width:48}}/>}</colgroup>
      <thead><tr><th style={th}>No.</th><th style={th}>Nama Produk</th>{isAuditor&&<th style={{...th,textAlign:"center"}}>Aksi</th>}</tr></thead>
      <tbody>
        {rows.map((r,i)=><tr key={r.id} style={{background:i%2===0?C.bg:C.bgAlt}}>
          <td style={{padding:"5px 8px",textAlign:"center",color:C.faint,fontSize:11}}>{i+1}</td>
          <td style={{padding:"5px 8px"}}>{r.nama}</td>
          {isAuditor&&<td style={{padding:"4px 6px",textAlign:"center"}}>
            <IconBtn title="Hapus" color="red" onClick={()=>setRows(rr=>rr.filter(x=>x.id!==r.id))}>🗑</IconBtn>
          </td>}
        </tr>)}
        {isAuditor&&<tr><td colSpan={3} style={{padding:"6px 8px",borderTop:`1px dashed ${C.border}`}}>
          {adding
            ? <div style={{display:"flex",gap:8,alignItems:"center"}}>
                <input value={newNama} onChange={e=>setNewNama(e.target.value)} autoFocus
                  placeholder="Nama produk..." onKeyDown={e=>{if(e.key==="Enter"&&newNama.trim()){setRows(r=>[...r,{id:Date.now(),nama:newNama.trim()}]);setNewNama("");setAdding(false);}if(e.key==="Escape"){setAdding(false);setNewNama("");}}}
                  style={{flex:1,border:`1px solid ${C.border}`,borderRadius:4,padding:"5px 8px",fontSize:12,fontFamily:font}}/>
                <button onClick={()=>{if(newNama.trim()){setRows(r=>[...r,{id:Date.now(),nama:newNama.trim()}]);setNewNama("");setAdding(false);}}}
                  style={{background:C.blue,color:"#fff",border:"none",borderRadius:4,padding:"5px 12px",fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:font}}>✓</button>
                <button onClick={()=>{setAdding(false);setNewNama("");}}
                  style={{background:"transparent",color:C.muted,border:`1px solid ${C.border}`,borderRadius:4,padding:"5px 10px",fontSize:12,cursor:"pointer",fontFamily:font}}>✕</button>
              </div>
            : <button onClick={()=>setAdding(true)} style={{background:"transparent",border:`1px dashed ${C.blue}`,
                borderRadius:4,padding:"5px 14px",fontSize:12,color:C.blue,cursor:"pointer",fontFamily:font,fontWeight:500}}>+ Tambah Produk</button>}
        </td></tr>}
      </tbody>
    </table>
  </div>;
}

// ─── Tim Auditor Tanda Tangan (bottom of report) ──────────────────────────────
function TimAuditorTTD({ reg }) {
  const AUDITORS_CONST = [
    {id:1,nama:"Dr. Yusraini Dian Inayati Siregar, M.Si.",nip:"197705122001122002"},
    {id:2,nama:"Trisan Andrean Putra, S.Si.",nip:""},
    {id:3,nama:"Adi Riyadhi",nip:""},
    {id:4,nama:"Dina Rizky Triani",nip:""},
  ];
  const getA = id => AUDITORS_CONST.find(a=>a.id===id);
  const team = [
    reg?.leadAuditor&&{peran:"Lead Auditor",a:getA(reg.leadAuditor)},
    reg?.auditor&&{peran:"Auditor",a:getA(reg.auditor)},
    reg?.observer&&{peran:"Observer",a:getA(reg.observer)},
  ].filter(Boolean);
  const th = {background:C.blue,color:"#fff",fontWeight:500,fontSize:11,padding:"7px 10px",textAlign:"left"};
  return <div style={{fontFamily:font}}>
    <table style={{width:"100%",borderCollapse:"collapse",fontSize:12}}>
      <thead><tr>
        <th style={{...th,width:28}}>No.</th>
        <th style={th}>Nama Auditor</th>
        <th style={th}>Peran</th>
        <th style={{...th,width:160}}>Tanda Tangan</th>
      </tr></thead>
      <tbody>{team.map((t,i)=><tr key={i} style={{background:i%2===0?C.bg:C.bgAlt}}>
        <td style={{padding:"14px 10px",textAlign:"center",color:C.faint,fontSize:11}}>{i+1}</td>
        <td style={{padding:"14px 10px",fontWeight:500}}>{t.a?.nama||"—"}</td>
        <td style={{padding:"14px 10px"}}><Badge color={t.peran==="Lead Auditor"?"blue":"gray"}>{t.peran}</Badge></td>
        <td style={{padding:"14px 10px",borderLeft:`1px solid ${C.borderLight}`}}>&nbsp;</td>
      </tr>)}</tbody>
    </table>
  </div>;
}

// ─── Profile Table (top of report) ───────────────────────────────────────────
function ProfileTable({ reg, mode, isAuditor }) {
  const AUDITORS_CONST = [
    {id:1,nama:"Dr. Yusraini Dian Inayati Siregar, M.Si."},
    {id:2,nama:"Trisan Andrean Putra, S.Si."},
    {id:3,nama:"Adi Riyadhi"},
    {id:4,nama:"Dina Rizky Triani"},
  ];
  const getA = id => AUDITORS_CONST.find(a=>a.id===id)?.nama||"—";
  const [agama,setAgama]=useState(reg?.agamaPemilik||"");

  const rows = [
    ["Nama Perusahaan", reg?.namaPU],
    ["Agama Pemilik", mode==="draft"
      ? <span style={{color:C.faint,fontStyle:"italic"}}>Diisi setelah audit</span>
      : isAuditor
        ? <input value={agama} onChange={e=>setAgama(e.target.value)} style={{border:`1px solid ${C.border}`,borderRadius:3,padding:"3px 7px",fontSize:13,fontFamily:font,width:240}} placeholder="Nama Pemilik / Agama"/>
        : agama||"—"],
    ["Nomor Pendaftaran", <span style={{fontFamily:mono,fontSize:12}}>{reg?.id}</span>],
    ["Alamat Perusahaan", reg?.alamatPU],
    ["Jenis Produk", reg?.jenisProduk],
    ["Jenis Pendaftaran", reg?.jenisPendaftaran],
    ["Tanggal Audit", reg?.tanggalAudit ? fmtDateLong(reg.tanggalAudit) : <Badge color="gold">Belum dijadwalkan</Badge>],
    ["Lead Auditor", getA(reg?.leadAuditor)],
    ["Auditor", getA(reg?.auditor)],
    reg?.observer && ["Observer", getA(reg.observer)],
  ].filter(Boolean);

  return <table style={{width:"100%",borderCollapse:"collapse",marginBottom:4}}>
    <tbody>{rows.map(([label,value],i)=><tr key={i} style={{background:i%2!==0?C.bg:C.bgAlt}}>
      <td style={{padding:"5px 8px",color:C.muted,width:160,whiteSpace:"nowrap",fontSize:13}}>{label}</td>
      <td style={{padding:"5px 8px",color:C.muted,width:12,fontSize:13}}>:</td>
      <td style={{padding:"5px 8px",fontWeight:500,fontSize:13}}>{value||"—"}</td>
    </tr>)}</tbody>
  </table>;
}

// ─── Section header ───────────────────────────────────────────────────────────
function SecHdr({ children }) {
  return <div style={{fontSize:11,fontWeight:600,color:C.blue,letterSpacing:"0.06em",
    textTransform:"uppercase",padding:"6px 0",margin:"20px 0 10px",
    borderBottom:`1.5px solid ${C.blueLight}`}}>{children}</div>;
}

// ─── Mode Tabs ────────────────────────────────────────────────────────────────
function ModeTabs({ mode, onChange, isAuditor }) {
  return <div style={{display:"flex",background:"rgba(255,255,255,0.12)",borderRadius:6,overflow:"hidden"}}>
    {MODES.map(m=><button key={m.key} onClick={()=>isAuditor&&onChange(m.key)} style={{
      background:mode===m.key?"rgba(255,255,255,0.22)":"none",border:"none",
      color:mode===m.key?"#fff":"rgba(255,255,255,0.7)",padding:"6px 14px",
      fontSize:12,fontFamily:font,cursor:isAuditor?"pointer":"default",fontWeight:500,transition:"all 0.15s"
    }}>{m.label}</button>)}
  </div>;
}

// ─── Lampiran section ─────────────────────────────────────────────────────────
function LampiranSection() {
  const items = ["Foto Audit","Sertifikat Penyelia Halal","Poster Kebijakan Halal","Denah Lokasi Produksi","Diagram Alir Produksi"];
  return <div style={{marginTop:24}}>
    {items.map((item,i)=><div key={i} style={{padding:"10px 14px",border:`1px solid ${C.borderLight}`,
      borderRadius:5,marginBottom:8,display:"flex",alignItems:"center",justifyContent:"space-between",
      background:C.bgAlt}}>
      <span style={{fontWeight:600,fontSize:12}}>Lampiran {item}</span>
      <Badge color="gray">Upload di tab Dokumentasi</Badge>
    </div>)}
  </div>;
}

// ─── Main Report Editor ───────────────────────────────────────────────────────
export default function HARSReportEditor({ reg, role }) {
  const isAuditor = role === "auditor";
  const isAdmin = role === "admin";
  const [mode,setMode]=useState("draft");
  const modeInfo = MODES.find(m=>m.key===mode);

  return <div style={{fontFamily:font,background:"#f0ede8",minHeight:"100vh"}}>
    {/* Sticky nav */}
    <nav style={{background:C.blue,color:"#fff",padding:"0 24px",display:"flex",
      alignItems:"center",justifyContent:"space-between",height:48,
      position:"sticky",top:0,zIndex:200,boxShadow:"0 2px 8px rgba(0,0,0,0.15)"}}>
      <div style={{display:"flex",alignItems:"center",gap:12}}>
        <span style={{fontSize:13,fontWeight:700,letterSpacing:"0.04em"}}>HARS</span>
        <span style={{opacity:0.4,fontSize:16}}>|</span>
        <span style={{fontSize:12,opacity:0.85}}>Laporan Audit · {reg?.namaPU||"—"}</span>
      </div>
      <div style={{display:"flex",alignItems:"center",gap:10}}>
        <ModeTabs mode={mode} onChange={setMode} isAuditor={isAuditor}/>
        <button onClick={()=>window.print()} style={{background:C.gold,border:"none",color:"#fff",
          padding:"5px 14px",borderRadius:5,fontSize:12,fontWeight:600,cursor:"pointer",fontFamily:font}}>
          ⎙ Cetak PDF
        </button>
      </div>
    </nav>

    {/* Document */}
    <div style={{maxWidth:860,margin:"24px auto",background:C.bg,
      border:`1px solid ${C.border}`,borderRadius:4,overflow:"hidden"}}>

      {/* Letterhead */}
      <div style={{padding:"18px 32px 14px",display:"flex",alignItems:"center",gap:20,
        borderBottom:`2px solid ${C.blue}`,position:"relative",overflow:"hidden"}}>
        <div style={{position:"absolute",top:0,right:0,width:0,height:0,borderStyle:"solid",
          borderWidth:"0 72px 72px 0",borderColor:`transparent #bed4ef transparent transparent`,opacity:0.7}}/>
        <div style={{position:"absolute",top:0,right:0,width:0,height:0,borderStyle:"solid",
          borderWidth:"0 44px 44px 0",borderColor:`transparent #dae8f7 transparent transparent`,opacity:0.8}}/>
        <img src={LOGO_SRC} alt="LPH UIN" style={{width:72,height:72,objectFit:"contain",flexShrink:0}}/>
        <div style={{flex:1}}>
          <div style={{fontSize:16,fontWeight:700,color:C.blue}}>LEMBAGA PEMERIKSA HALAL</div>
          <div style={{fontSize:15,fontWeight:700,color:C.blue}}>UIN SYARIF HIDAYATULLAH JAKARTA</div>
          <div style={{fontSize:11,color:C.muted,marginTop:5,lineHeight:1.5,borderTop:`1px solid #dce8f8`,paddingTop:5}}>
            Gedung Wisma Usaha UIN Syarif Hidayatullah Jakarta Lantai 3, Jl. Ir H. Juanda No. 95, Cempaka Putih, Ciputat, Tangerang Selatan, Banten 15412
            <br/>Telp: 08971740444 &nbsp;·&nbsp; Email: lph@apps.uinjkt.ac.id
          </div>
        </div>
      </div>

      {/* Title bar */}
      <div style={{background:C.blue,color:"#fff",textAlign:"center",padding:"14px 32px"}}>
        <div style={{fontSize:14,fontWeight:600,letterSpacing:"0.04em"}}>{modeInfo.title}</div>
        <div style={{fontSize:12,opacity:0.85,marginTop:2}}>LPH UIN SYARIF HIDAYATULLAH JAKARTA</div>
      </div>

      {/* Mode ribbon */}
      <div style={{background:C.goldLight,borderBottom:`1px solid #e8d58a`,
        padding:"7px 32px",display:"flex",alignItems:"center",gap:10}}>
        <span style={{background:mode==="final"?C.blue:C.gold,color:"#fff",fontSize:10,fontWeight:600,
          padding:"2px 8px",borderRadius:3,letterSpacing:"0.05em"}}>{modeInfo.badge}</span>
        <span style={{fontSize:11,color:C.gold}}>{modeInfo.desc}</span>
        {isAdmin&&<span style={{fontSize:11,color:C.muted,marginLeft:"auto"}}>
          Mode diubah oleh auditor yang bertugas
        </span>}
      </div>

      {/* Content */}
      <div style={{padding:"24px 32px"}}>
        <SecHdr>Profil Perusahaan</SecHdr>
        <ProfileTable reg={reg} mode={mode} isAuditor={isAuditor}/>

        <SecHdr>Daftar Fasilitas</SecHdr>
        <FasilitasTable reg={reg} mode={mode} isAuditor={isAuditor}/>

        <SecHdr>Penyelia Halal Perusahaan</SecHdr>
        <PenyeliaTable reg={reg} isAuditor={isAuditor}/>

        <SecHdr>Daftar Produk</SecHdr>
        <ProdukTable isAuditor={isAuditor}/>

        <SecHdr>Daftar Bahan</SecHdr>
        <BahanTable mode={mode} isAuditor={isAuditor}/>

        <SecHdr>Kriteria SJPH</SecHdr>
        <KriteriaTable mode={mode} isAuditor={isAuditor}/>

        {/* Tim Auditor TTD */}
        <SecHdr>Tim Auditor</SecHdr>
        <TimAuditorTTD reg={reg}/>

        {/* Verdict */}
        <div style={{background:C.blueLight,border:`1.5px solid ${C.blue}`,borderRadius:4,
          padding:"12px 20px",margin:"20px 0",display:"flex",alignItems:"center",gap:12}}>
          <span style={{fontSize:24}}>✓</span>
          <div>
            <div style={{fontSize:11,color:C.muted}}>Keterangan Laporan Hasil Audit</div>
            <div style={{fontSize:15,fontWeight:600,color:C.blue}}>LULUS</div>
          </div>
        </div>

        {/* Tanggal & Signature */}
        <div style={{display:"flex",justifyContent:"flex-end",margin:"24px 0 8px"}}>
          <div style={{textAlign:"center",width:220}}>
            <div style={{fontSize:12}}>
              Tangerang Selatan,{" "}
              <span contentEditable suppressContentEditableWarning
                style={{borderBottom:`1px dashed ${C.border}`,minWidth:100,display:"inline-block"}}>
                {reg?.tanggalAudit?fmtDate(reg.tanggalAudit):"__________"}
              </span>
            </div>
            <div style={{fontSize:12,color:C.muted,marginTop:4}}>Diketahui Oleh,<br/>Direktur LPH</div>
            <div style={{height:56}}/>
            <span style={{fontWeight:600,fontSize:13,borderTop:`1.5px solid ${C.text}`,
              paddingTop:4,display:"inline-block"}}
              contentEditable suppressContentEditableWarning>
              Dr. Yusraini Dian Inayati Siregar, M.Si.
            </span>
            <div style={{fontSize:11,color:C.muted,marginTop:2}}>NIP. 197705122001122002</div>
          </div>
        </div>

        {/* Lampiran */}
        <SecHdr>Lampiran</SecHdr>
        <LampiranSection/>
      </div>
    </div>
  </div>;
}
